"""
account module - handles core account functionality
"""
from typing import Optional, List
from dataclasses import dataclass

@dataclass
class AccountService:
    id: int
    name: str
    status: str = "active"
    created_at: Optional[str] = None

    def validate(self) -> bool:
        """Validate the AccountService instance."""
        if not self.name:
            raise ValueError("Name is required")
        return True

    def to_dict(self) -> dict:
        """Convert to dictionary representation."""
        return {{
            "id": self.id,
            "name": self.name,
            "status": self.status,
            "created_at": self.created_at
        }}

import {{ Injectable }} from '@nestjs/common';
import {{ AccountService }} from './models/account.model';
import {{ AccountServiceRepository }} from './repositories/account.repository';

@Injectable()
export class AccountServiceService {{
  constructor(
    private readonly repository: AccountServiceRepository,
  ) {{}}

  async findAll(): Promise<AccountService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<AccountService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<AccountService>): Promise<AccountService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<AccountService>): Promise<AccountService> {{
    return this.repository.update(id, data);
  }}
}}
